# Conceptual guardrails (not production code)
MAX_REQUESTS_PER_MINUTE_PER_SITE = 10
MIN_DELAY_BETWEEN_REQUESTS = 2.0  # seconds
MAX_RETRIES = 3
BACKOFF_DELAYS = [2, 5, 10]  # seconds

ALLOWED_DOMAINS = [
    "example.com",
    "publicdata.org",
]

def is_allowed(url):
    domain = extract_domain(url)
    return domain in ALLOWED_DOMAINS

def scrape_with_guardrails(url, goal, fields):
    if not is_allowed(url):
        raise ValueError("Domain not allowed for scraping")

    for attempt in range(MAX_RETRIES):
        response = playwright_request(url)  # with rate limits and delays

        if response.status == 429 or response.status == 403:
            if attempt >= MAX_RETRIES - 1:
                raise BlockedException("Site blocked after retries")
            sleep(BACKOFF_DELAYS[attempt])
            continue

        if "captcha" in response.text.lower():
            raise CaptchaEncountered("CAPTCHA detected; stopping")

        data = extract_fields(response, fields)
        return {"url": url, "items": data, "notes": ["Extraction completed"]}

    raise BlockedException("Repeated blocks")
